// Entrada esperada (Chat Trigger):
// { sessionId, action, chatInput: "https://fonestar.com max=200" }

const raw = String($json.chatInput ?? '').trim();
if (!raw) throw new Error('Falta chatInput. Ej: https://fonestar.com max=200');

// Normalizar texto
const text = raw
  .replace(/[\u200B-\u200D\uFEFF]/g, '')   // invisibles
  .replace(/\r\n|\r|\n/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// max=NN (opcional)
let maxProducts = 200;
const mm = text.match(/(?:^|\s)max\s*=\s*(\d+)/i);
if (mm?.[1]) {
  const n = parseInt(mm[1], 10);
  if (Number.isFinite(n)) maxProducts = Math.min(Math.max(n, 1), 2000);
}


// chatId=NNN (opcional, para enviar el JSON por Telegram)
let chatId = null;
const mc = text.match(/(?:^|\s)chatid\s*=\s*(\d+)/i);
if (mc?.[1]) {
  const n = parseInt(mc[1], 10);
  if (Number.isFinite(n)) chatId = n;
}

// Sacar URL/dominio (primer token razonable)
const tokens = text.split(' ');
let candidate = '';

for (let t of tokens) {
  t = t.trim()
    .replace(/^[<("'[{]+/g, '')
    .replace(/[>\)"'\]}.,;:!?]+$/g, '');
  if (!t) continue;

  if (
    t.startsWith('http://') ||
    t.startsWith('https://') ||
    t.startsWith('//') ||
    t.startsWith('www.') ||
    t.includes('.')
  ) {
    candidate = t;
    break;
  }
}

if (!candidate) {
  throw new Error('No encontré URL/dominio en el mensaje. Ej: https://fonestar.com max=200');
}

// Normalizar URL (sin usar new URL)
candidate = candidate
  .replace(/(https?)\s*:\s*\/\//i, '$1://') // "https : //"
  .replace(/(https?)\s+\/\//i, '$1://');    // "https //"

if (candidate.startsWith('//')) candidate = 'https:' + candidate;
if (candidate.startsWith('www.')) candidate = 'https://' + candidate;
if (!/^https?:\/\//i.test(candidate)) candidate = 'https://' + candidate;

// origin
const mOrigin = candidate.match(/^(https?:\/\/[^\/?#]+)/i);
if (!mOrigin) throw new Error(`URL inválida: "${candidate}"`);

const origin = mOrigin[1];

return [{
  json: {
    inputText: text,
    targetUrl: candidate,
    origin,
    maxProducts,
    userAgent: 'Mozilla/5.0 (n8n-scraper)',
    chatId
  }
}];

/**
 * Build Candidates (simple y robusto)
 * Entrada:
 *  - origin (desde Parse Chat Command, vía Include Input Data o Merge)
 *  - robots.txt en data/body/text
 * Salida:
 *  - items { candidateUrl }
 */

// --- Obtener origin de forma robusta ---
let origin = $json.origin;

if (!origin) {
  try {
    origin = $items('Parse Chat Command')[0].json.origin;
  } catch (e) {}
}

origin = String(origin || '').replace(/\/+$/,'').trim();

if (!origin) {
  throw new Error('Falta origin. Asegura Include Input Data o usa Merge.');
}

// --- Obtener contenido robots.txt ---
function getRobots(obj) {
  for (const k of ['body','data','text','response']) {
    if (typeof obj?.[k] === 'string' && obj[k].trim()) return obj[k];
  }
  for (const v of Object.values(obj || {})) {
    if (typeof v === 'string' && v.trim()) return v;
  }
  return '';
}

const robotsStr = getRobots($json);

if (!robotsStr) {
  // Si no hay robots, seguimos con defaults
  console.log('robots.txt vacío, usando fallbacks.');
}

// --- Extraer Sitemap: del robots ---
const found = [];
const lines = String(robotsStr || '').split(/\r?\n/);

for (const line of lines) {
  const match = line.match(/^\s*sitemap:\s*(\S+)/i);
  if (match && match[1]) {
    found.push(match[1].trim());
  }
}

// --- Fallbacks típicos ---
const defaults = [
  origin + '/sitemap.xml',
  origin + '/sitemap_index.xml',
  origin + '/sitemap-index.xml',
  origin + '/sitemapindex.xml',
  origin + '/wp-sitemap.xml'
];

// Opcionales HTML (por si no hay XML)
const html = [
  origin + '/sitemap',
  origin + '/en/sitemap',
  origin + '/es/sitemap',
  origin + '/de/sitemap'
];

// --- Combinar y deduplicar ---
const candidates = [...found, ...defaults, ...html]
  .filter(Boolean);

const uniq = [...new Set(candidates)];

// --- Output ---
return uniq.map(u => ({
  json: {
    candidateUrl: u
  }
}));

/**
 * Pick + Parse Candidate (robusto y sencillo)
 * Limitado a maxProducts (200 por defecto)
 */

// 1) Obtener origin y meta
const firstIn = $input.first()?.json ?? {};
const meta = (() => {
  try { return $items('Parse Chat Command')[0].json; } catch (e) { return {}; }
})();

const origin = firstIn.origin || meta.origin || '';
const MAX_ITEMS = meta.maxProducts || 200;

// limpiar invisibles
const clean = (s) => String(s || '').replace(/[\u200B-\u200D\uFEFF]/g, '').trim();

// host sin new URL
const originHost = (() => {
  const m = clean(origin).match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : '';
})();

// 2) Obtener bodies
const all = $input.all().map(x => x.json);

function getBody(o) {
  for (const k of ['body', 'data', 'response', 'text']) {
    if (typeof o?.[k] === 'string' && o[k].trim()) return o[k];
  }
  for (const v of Object.values(o || {})) {
    if (typeof v === 'string' && v.length > 50) return v;
  }
  return '';
}

function decodeEntities(s) {
  return String(s || '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function toAbsoluteUrl(href) {
  const h = clean(decodeEntities(href));
  if (!h) return '';

  if (
    h.startsWith('#') ||
    h.startsWith('mailto:') ||
    h.startsWith('tel:') ||
    h.startsWith('javascript:')
  ) return '';

  if (/^https?:\/\//i.test(h)) return h;

  if (h.startsWith('//')) {
    const scheme = clean(origin).startsWith('http://') ? 'http:' : 'https:';
    return scheme + h;
  }

  if (origin) {
    if (h.startsWith('/')) return clean(origin).replace(/\/+$/,'') + h;
    return clean(origin).replace(/\/+$/,'') + '/' + h;
  }

  return '';
}

function sameHost(url) {
  if (!originHost) return true;
  const m = clean(url).match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() === originHost : false;
}

// 3) Elegir mejor body
let bestScore = 0;
let bestBody = '';

for (const o of all) {
  const body = clean(getBody(o));
  if (!body) continue;

  const b = body.toLowerCase();
  let score = 0;
  if (b.includes('<urlset')) score = 3;
  else if (b.includes('<sitemapindex')) score = 2;
  else if (b.includes('<html')) score = 1;

  if (score > bestScore) {
    bestScore = score;
    bestBody = body;
  }
}

// 4) Parsear
let pageUrls = [];
let childSitemaps = [];

if (bestScore === 3) {
  const locRe = /<loc>\s*([^<\s]+)\s*<\/loc>/gi;
  for (const m of bestBody.matchAll(locRe)) {
    const u = clean(decodeEntities(m[1]));
    if (!u) continue;
    if (!sameHost(u)) continue;
    pageUrls.push(u);
  }
} else if (bestScore === 2) {
  const locRe = /<loc>\s*([^<\s]+)\s*<\/loc>/gi;
  for (const m of bestBody.matchAll(locRe)) {
    const u = clean(decodeEntities(m[1]));
    if (!u) continue;

    const lu = u.toLowerCase();
    const looksSitemap = lu.includes('sitemap') || lu.endsWith('.xml') || lu.endsWith('.xml.gz');
    if (looksSitemap) childSitemaps.push(u);
  }
} else if (bestScore === 1) {
  const hrefRe = /href=["']([^"']+)["']/gi;
  for (const m of bestBody.matchAll(hrefRe)) {
    const abs = toAbsoluteUrl(m[1]);
    if (!abs) continue;
    if (!sameHost(abs)) continue;

    const lu = abs.toLowerCase();
    const looksSitemap = lu.includes('sitemap') || lu.endsWith('.xml') || lu.endsWith('.xml.gz');
    if (looksSitemap) childSitemaps.push(abs);
    else pageUrls.push(abs);
  }
}

// dedupe
pageUrls = [...new Set(pageUrls)];
childSitemaps = [...new Set(childSitemaps)];

// 🔒 LIMITAR RESULTADOS
pageUrls = pageUrls.slice(0, MAX_ITEMS);

if (pageUrls.length < MAX_ITEMS) {
  childSitemaps = childSitemaps.slice(0, MAX_ITEMS - pageUrls.length);
} else {
  childSitemaps = [];
}

// 5) Output
const out = [];

if (pageUrls.length === 0) {
  out.push({ json: { kind: 'pageUrl', url: '', isDummy: true } });
} else {
  for (const u of pageUrls) {
    out.push({ json: { kind: 'pageUrl', url: u, isDummy: false } });
  }
}

if (childSitemaps.length === 0) {
  out.push({ json: { kind: 'childSitemap', url: '', isDummy: true } });
} else {
  for (const u of childSitemaps) {
    out.push({ json: { kind: 'childSitemap', url: u, isDummy: false } });
  }
}

return out;

/**
 * Parse Child Sitemap (simple y robusto)
 * Entrada: items con el XML del child sitemap en body/data/text/response
 * Output: items { kind:'pageUrl', url, isDummy }
 */


// meta (para límites)
let meta = {};
try { meta = $items('Parse Chat Command')[0].json; } catch (e) { meta = {}; }
const CAP = Math.min((meta.maxProducts || 200) * 5, 5000);

// 1) origin / host (robusto)
const firstIn = $input.first()?.json ?? {};
let origin = firstIn.origin;

if (!origin) {
  // fallback: intentar leer del nodo Parse Chat Command si existe
  try { origin = $items('Parse Chat Command')[0].json.origin; } catch (e) {}
}

origin = String(origin || '').trim();

// host sin new URL()
const originHost = (() => {
  const m = origin.match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : '';
})();

function getBody(o) {
  for (const k of ['body', 'data', 'response', 'text']) {
    if (typeof o?.[k] === 'string' && o[k].trim()) return o[k];
  }
  for (const v of Object.values(o || {})) {
    if (typeof v === 'string' && v.length > 50) return v;
  }
  return '';
}

function decodeEntities(s) {
  return String(s || '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function strip(s) {
  return String(s || '')
    .replace(/[\u200B-\u200D\uFEFF]/g, '') // invisibles
    .trim();
}

function sameHost(url) {
  if (!originHost) return true; // si no sabemos host, no filtramos
  const m = strip(url).match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() === originHost : false;
}

function toAbsolute(u) {
  let s = strip(decodeEntities(u));
  if (!s) return '';

  // si ya es absoluta
  if (/^https?:\/\//i.test(s)) return s;

  // protocol-relative
  if (s.startsWith('//')) {
    const scheme = origin.startsWith('http://') ? 'http:' : 'https:';
    return scheme + s;
  }

  // relativa
  if (origin) {
    const base = origin.replace(/\/+$/g, '');
    if (s.startsWith('/')) return base + s;
    return base + '/' + s;
  }

  return '';
}

// 2) parse <loc> en todos los inputs
const all = $input.all().map(i => i.json);
const pageUrls = [];

const locRe = /<loc>\s*([^<\s]+)\s*<\/loc>/gi;

for (const o of all) {
  const body = strip(getBody(o));
  if (!body) continue;

  for (const m of body.matchAll(locRe)) {
    const rawLoc = m[1];
    const abs = toAbsolute(rawLoc);
    if (!abs) continue;

    const lu = abs.toLowerCase();
    // excluir sitemaps
    if (lu.endsWith('.xml') || lu.endsWith('.xml.gz') || lu.includes('sitemap')) continue;

    if (!sameHost(abs)) continue;

    pageUrls.push(abs);
    if (pageUrls.length >= CAP) break;
  }
  if (pageUrls.length >= CAP) break;
}

// 3) dedupe + output
const uniq = [...new Set(pageUrls)].slice(0, CAP);

if (uniq.length === 0) {
  return [{ json: { kind: 'pageUrl', url: '', isDummy: true } }];
}

return uniq.map(u => ({ json: { kind: 'pageUrl', url: u, isDummy: false } }));

/**
 * Filter + Limit URLs (sin new URL)
 * Entrada: items { kind:'pageUrl', url }
 * Usa meta de Parse Chat Command: origin + maxProducts
 * Salida: items { url } o { noUrls:true }
 */

// --- meta robusto ---
let meta = {};
try { meta = $items('Parse Chat Command')[0].json; } catch (e) { meta = {}; }

const origin = String(meta.origin || '').trim();
const max = Number(meta.maxProducts || 200);

if (!origin) throw new Error('Falta origin (desde Parse Chat Command).');

const originHost = (() => {
  const m = origin.match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : '';
})();

const originScheme = origin.startsWith('http://') ? 'http:' : 'https:';

const cleanStr = (s) =>
  String(s || '')
    .replace(/[\u200B-\u200D\uFEFF]/g, '') // invisibles
    .replace(/\s+/g, ' ')
    .trim();

const decodeEntities = (s) =>
  String(s || '').replace(/&amp;/g, '&');

function getHost(u) {
  const m = cleanStr(u).match(/^https?:\/\/([^\/?#]+)/i);
  return m ? m[1].toLowerCase() : '';
}

function getPath(u) {
  // devuelve pathname sin query/fragment
  const s = cleanStr(u);
  const m = s.match(/^https?:\/\/[^\/?#]+(\/[^?#]*)?/i);
  return (m && m[1]) ? m[1] : '/';
}

function normalizeUrl(u) {
  let s = cleanStr(decodeEntities(u));

  if (!s) return '';

  // arreglos básicos si vienen partidos
  s = s.replace(/(https?)\s*:\s*\/\//i, '$1://');
  s = s.replace(/(https?)\s+\/\//i, '$1://');

  // quitar fragment
  s = s.split('#')[0];

  // protocol-relative
  if (s.startsWith('//')) s = originScheme + s;

  // relativo a origin
  if (s.startsWith('/')) s = origin.replace(/\/+$/,'') + s;

  // relativo sin slash
  if (!/^https?:\/\//i.test(s)) s = origin.replace(/\/+$/,'') + '/' + s;

  return s;
}

// --- recolectar urls pageUrl ---
const urls = [];
for (const it of $input.all()) {
  const j = it.json || {};
  if (j.kind === 'pageUrl' && j.url) urls.push(j.url);
}

// --- dedupe (antes de normalizar) ---
const ded = [...new Set(urls.map(cleanStr).filter(Boolean))];

// --- filtros ---
const badExt = [
  '.jpg','.jpeg','.png','.gif','.webp','.svg',
  '.css','.js','.pdf','.zip','.rar','.7z',
  '.mp4','.mp3','.wav','.ico',
  '.woff','.woff2','.ttf','.eot'
];

const cleaned = [];

for (const raw of ded) {
  const abs = normalizeUrl(raw);
  if (!abs) continue;

  // filtrar host (si lo conocemos)
  if (originHost) {
    const h = getHost(abs);
    if (!h || h !== originHost) continue;
  }

  const p = getPath(abs).toLowerCase();
  if (badExt.some(ext => p.endsWith(ext))) continue;

  cleaned.push(abs);
}

// dedupe final
const cleanedUniq = [...new Set(cleaned)];

// --- priorizar posibles páginas de producto ---
const productHints = [
  '/product/','/products/','/producto/','/productos/',
  '/shop/','/store/','/tienda/',
  '/catalog','/catalogo',
  '/item/','/p/','/prod'
];

const hinted = cleanedUniq.filter(u =>
  productHints.some(h => u.toLowerCase().includes(h))
);

// regla: si hay suficientes “hinted”, usa esas; si no, usa todas
const threshold = Math.min(50, max);
const chosen = (hinted.length >= threshold) ? hinted : cleanedUniq;

const final = chosen.slice(0, max);

if (final.length === 0) {
  return [{ json: { noUrls: true } }];
}

return final.map(u => ({ json: { url: u } }));

/**
 * Parse Product Data (multimarca, robusto)
 * Entrada: { url } + HTML en body/data/response/text
 * Salida: { url, isProduct, name, price, currency, category, sku, detectedBy }
 */

const meta = (() => { try { return $items('Parse Chat Command')[0].json; } catch (e) { return {}; } })();

function getBody(o) {
  for (const k of ['body','data','response','text']) {
    if (typeof o?.[k] === 'string' && o[k].trim()) return o[k];
  }
  for (const v of Object.values(o || {})) {
    if (typeof v === 'string' && v.length > 200) return v;
  }
  return '';
}

const clean = (s) => String(s || '')
  .replace(/[\u200B-\u200D\uFEFF]/g, '')
  .trim();

const stripTags = (s) => clean(String(s || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' '));

function decodeEntities(s) {
  return String(s || '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function typeHas(t, val) {
  if (!t) return false;
  if (Array.isArray(t)) return t.map(x => String(x)).some(x => x === val || x.includes(val));
  const s = String(t);
  return s === val || s.includes(val);
}

function parseNumberMaybe(x) {
  if (x === null || x === undefined) return null;
  const s = String(x)
    .replace(/\s/g, '')
    .replace(/\./g, '')              // miles
    .replace(/,(\d{2})$/, '.$1')      // decimal europeo al final
    .replace(/[^0-9.]/g, '');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : null;
}

function currencyFromSymbol(s) {
  const t = String(s || '');
  if (t.includes('€')) return 'EUR';
  if (t.includes('$')) return 'USD';
  if (t.includes('£')) return 'GBP';
  if (t.includes('CHF')) return 'CHF';
  return null;
}

function firstMeta(html, attr, key) {
  // attr: 'property' o 'name' o 'itemprop'
  const re = new RegExp(`<meta[^>]+${attr}=["']${key}["'][^>]*>`, 'i');
  const m = html.match(re);
  if (!m) return null;
  const tag = m[0];
  const c = tag.match(/content=["']([^"']+)["']/i);
  return c ? clean(decodeEntities(c[1])) : null;
}

function firstTagContent(html, tagName) {
  const re = new RegExp(`<${tagName}[^>]*>([\\s\\S]*?)</${tagName}>`, 'i');
  const m = html.match(re);
  return m ? stripTags(m[1]) : '';
}

function firstH1(html) {
  const re = /<h1[^>]*>([\s\S]*?)<\/h1>/i;
  const m = html.match(re);
  return m ? stripTags(m[1]) : '';
}

function extractJsonLdObjects(html) {
  const re = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
  const scripts = [];
  let m;
  while ((m = re.exec(html)) !== null) scripts.push(clean(m[1]));
  const objs = [];
  for (const s0 of scripts) {
    if (!s0) continue;
    const s = s0
      .replace(/^\s*<!--/,'')
      .replace(/-->\s*$/,'')
      .trim();
    try {
      const parsed = JSON.parse(s);
      const arr = Array.isArray(parsed) ? parsed : [parsed];
      for (const o of arr) {
        if (o && typeof o === 'object') {
          if (Array.isArray(o['@graph'])) {
            for (const g of o['@graph']) if (g && typeof g === 'object') objs.push(g);
          }
          objs.push(o);
        }
      }
    } catch (e) {
      // ignorar JSON-LD inválido
    }
  }
  return objs;
}

function looksLikeAddToCart(html) {
  const h = html.toLowerCase();
  return h.includes('add-to-cart') || h.includes('add_to_cart') || h.includes('variations_form') || h.includes('product-form');
}

function normalizeCategoryFromUrl(url) {
  try {
    // si URL constructor no está disponible o falla, usamos regex
    const m = String(url).match(/^https?:\/\/[^\/?#]+(\/[^?#]*)?/i);
    const path = m && m[1] ? m[1] : '/';
    const segs = path.split('/').filter(Boolean);

    // quitar idioma común
    const langs = new Set(['es','en','fr','de','pt','it','nl','pl','sv','no','da','fi','cs']);
    const cleaned = segs.filter((s, idx) => !(idx === 0 && langs.has(s.toLowerCase())));

    // quedarnos con 1-3 segmentos previos al slug final
    if (cleaned.length <= 1) return '';
    const head = cleaned.slice(0, Math.min(3, cleaned.length - 1));
    return head.map(s => decodeURIComponent(s)).join(' > ');
  } catch (e) {
    return '';
  }
}

const out = [];
for (const it of $input.all()) {
  const j = it.json || {};
  const url = clean(j.url || j.link || j.href || '');
  const html = clean(getBody(j));

  if (!url) {
    out.push({ json: { url: '', isProduct: false, detectedBy: 'no_url' } });
    continue;
  }

  if (!html || html.length < 300) {
    out.push({ json: { url, isProduct: false, detectedBy: 'no_html' } });
    continue;
  }

  const detected = [];
  const objs = extractJsonLdObjects(html);

  let prod = null;
  let bc = null;

  for (const o of objs) {
    if (o && typeHas(o['@type'], 'Product')) { prod = o; break; }
  }
  for (const o of objs) {
    if (o && typeHas(o['@type'], 'BreadcrumbList')) { bc = o; break; }
  }

  // --- NAME ---
  let name = prod?.name ? clean(prod.name) : '';
  if (!name) name = firstMeta(html, 'property', 'og:title') || '';
  if (!name) name = firstMeta(html, 'name', 'twitter:title') || '';
  if (!name) name = firstH1(html) || '';
  if (!name) name = firstTagContent(html, 'title').split('|')[0].split('-')[0].trim();

  // --- SKU ---
  let sku = prod?.sku ? clean(prod.sku) : '';
  if (!sku) {
    const skuMeta = firstMeta(html, 'itemprop', 'sku') || firstMeta(html, 'name', 'sku');
    if (skuMeta) sku = skuMeta;
  }
  if (!sku) {
    const mSku = html.match(/(?:SKU|Ref\.?|Referencia|Item\s*No\.?)\s*[:\-]?\s*([A-Z0-9][A-Z0-9\-_.\/]+)/i);
    if (mSku) sku = clean(mSku[1]);
  }

  // --- PRICE & CURRENCY ---
  let price = null;
  let currency = null;

  // JSON-LD offers
  if (prod?.offers) {
    const off = Array.isArray(prod.offers) ? prod.offers[0] : prod.offers;
    currency = off?.priceCurrency ? clean(off.priceCurrency) : currency;
    const pr = off?.price ?? off?.priceSpecification?.price ?? null;
    const pnum = parseNumberMaybe(pr);
    if (pnum !== null) price = pnum;
    detected.push('jsonld');
  }

  // meta tags fallback
  if (price === null) {
    const p = firstMeta(html, 'property', 'product:price:amount')
           || firstMeta(html, 'property', 'og:price:amount')
           || firstMeta(html, 'name', 'product:price:amount')
           || firstMeta(html, 'name', 'price')
           || null;
    const c = firstMeta(html, 'property', 'product:price:currency')
           || firstMeta(html, 'property', 'og:price:currency')
           || firstMeta(html, 'name', 'currency')
           || null;

    const pnum = parseNumberMaybe(p);
    if (pnum !== null) {
      price = pnum;
      currency = currency || (c ? clean(c) : null);
      detected.push('meta');
    }
  }

  // microdata itemprop price
  if (price === null) {
    const mP = html.match(/itemprop=["']price["'][^>]*(?:content=["']([^"']+)["']|>\s*([^<]+)\s*<)/i);
    if (mP) {
      const pnum = parseNumberMaybe(mP[1] || mP[2]);
      if (pnum !== null) {
        price = pnum;
        detected.push('microdata');
      }
    }
    const mC = html.match(/itemprop=["']priceCurrency["'][^>]*(?:content=["']([^"']+)["']|>\s*([^<]+)\s*<)/i);
    if (mC) currency = currency || clean(mC[1] || mC[2]);
  }

  // woocommerce / common price blocks
  if (price === null) {
    const mW = html.match(/woocommerce-Price-amount[^>]*>\s*([^<]{1,40})</i);
    if (mW) {
      const txt = clean(stripTags(mW[1]));
      const pnum = parseNumberMaybe(txt);
      if (pnum !== null) {
        price = pnum;
        currency = currency || currencyFromSymbol(txt);
        detected.push('regex');
      }
    }
  }

  // currency from symbols anywhere near price
  if (!currency && price !== null) {
    // buscar símbolo cerca de números
    const mSym = html.match(/([€$£])\s*[0-9]/);
    if (mSym) currency = currencyFromSymbol(mSym[1]);
  }

  // --- CATEGORY ---
  let category = '';
  if (bc?.itemListElement) {
    const els = Array.isArray(bc.itemListElement) ? bc.itemListElement : [bc.itemListElement];
    const names = [];
    for (const el of els) {
      const item = el?.item ? el.item : el;
      const nm = item?.name || el?.name || '';
      if (nm) names.push(clean(nm));
    }
    const cleaned = names.filter(x => x && !['home','inicio','start'].includes(x.toLowerCase()));
    if (cleaned.length > 0) {
      const last = cleaned[cleaned.length - 1];
      if (name && last && last.toLowerCase() === name.toLowerCase()) cleaned.pop();
      category = cleaned.join(' > ');
      detected.push('breadcrumb');
    }
  }
  if (!category) category = normalizeCategoryFromUrl(url);
  if (!category) category = 'Sin categoria';

  // --- isProduct heuristic ---
  const ogType = (firstMeta(html, 'property', 'og:type') || '').toLowerCase();
  const hasProductSignals = looksLikeAddToCart(html) || ogType.includes('product');
  const isProduct = !!prod || (name && hasProductSignals) || (name && price !== null);

  out.push({
    json: {
      url,
      isProduct,
      name: name || null,
      price,
      currency: currency || null,
      category,
      sku: sku || null,
      detectedBy: detected.length ? [...new Set(detected)].join(',') : null
    }
  });
}

return out;

/**
 * Build JSON File (robusto y compatible con tu entorno)
 * Genera binario JSON listo para enviar por Telegram
 */

// --- META ---
let meta = {};
try { meta = $items('Parse Chat Command')[0].json; } catch (e) { meta = {}; }

const chatId = meta.chatId || null;
const src = meta.targetUrl || '';
const origin = meta.origin || '';
const now = new Date().toISOString();

// --- INPUT ITEMS ---
const items = $input.all().map(i => i.json || {});

// --- PRODUCTOS VÁLIDOS ---
const validProducts = items.filter(p => p && p.isProduct && p.name);

// --- LISTA PLANA ---
const products = validProducts.map(p => ({
  name: p.name || null,
  price: p.price ?? null,
  currency: p.currency ?? null,
  url: p.url || null,
  sku: p.sku || null
}));

// --- AGRUPAR POR CATEGORÍA ---
const byCat = new Map();

for (const p of validProducts) {
  let c = (p.category || 'Sin categoria');
  c = String(c).trim();
  if (!c) c = 'Sin categoria';

  if (!byCat.has(c)) byCat.set(c, []);

  byCat.get(c).push({
    name: p.name || null,
    price: p.price ?? null,
    currency: p.currency ?? null,
    url: p.url || null,
    sku: p.sku || null
  });
}

// --- ORDENAR CATEGORÍAS ---
const categories = [...byCat.entries()]
  .sort((a, b) => a[0].localeCompare(b[0]))
  .map(([name, prods]) => ({
    name,
    products: prods
  }));

// --- CATALOGO FINAL ---
const catalog = {
  source: src,
  generated_at: now,
  total_products: products.length,
  categories
};

const jsonStr = JSON.stringify(catalog, null, 2);

// --- HOST SEGURO (sin new URL) ---
let host = 'unknown';

const hostMatch = String(origin).match(/^https?:\/\/([^\/?#]+)/i);
if (hostMatch) {
  host = hostMatch[1].replace(/[^a-zA-Z0-9.-]/g, '_');
}

const fileName = `catalog_${host}_${Date.now()}.json`;

// --- OUTPUT BINARIO ---
return [{
  json: {
    chatId,
    fileName,
    total_products: products.length
  },
  binary: {
    data: {
      data: Buffer.from(jsonStr, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName
    }
  }
}];
